pub fn parse(allocator: NeverFailingAllocator, name: []const u8, arg: []const u8, errorMessage: *List(u8)) error{ParseError}!Path {
		if (arg[0] != '/') {
			errorMessage.print(allocator, "Permission path for <{s}> doesn't begin with a \"/\", got: {s}", .{name, arg});
			return error.ParseError;
		}
		return .{.path = arg};
	}

pub fn init(pos: Vec2f, maxWidth: f32, text: []const u8, alignment: TextBuffer.Alignment) *Label {
	const self = main.globalAllocator.create(Label);
	self.* = Label{
		.text = TextBuffer.init(main.globalAllocator, text, .{}, false, alignment),
		.pos = pos,
		.size = undefined,
	};
	self.size = self.text.calculateLineBreaks(fontSize, maxWidth);
	return self;
}
